import React from 'react';

const Footer = () => {
  const scrollToTop = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <footer>
      <div className="footer-copy">
        © 2024 Shrabanti Saha. Built with React &amp; passion for responsive design. Exploring ML frontiers.
      </div>
      <button className="footer-top-btn" onClick={scrollToTop}>
        ↑ Back to Top
      </button>
    </footer>
  );
};

export default Footer;
